# -*- coding: utf-8 -*-
from fpdf import FPDF
FD="/usr/share/fonts/truetype/dejavu"
NAVY=(20,35,63); INK=(33,37,43); GREY=(95,102,112); SOFT=(238,241,247); LINE=(214,219,228); WHITE=(255,255,255); ACCENT=(176,141,87); GREEN=(40,110,70)
class M(FPDF):
    def __init__(self):
        super().__init__("P","mm","A4"); self.set_auto_page_break(True,16)
        self.add_font("S","",f"{FD}/DejaVuSans.ttf"); self.add_font("S","B",f"{FD}/DejaVuSans-Bold.ttf")
        self.add_font("R","",f"{FD}/DejaVuSerif.ttf"); self.add_font("R","B",f"{FD}/DejaVuSerif-Bold.ttf")
        self.set_margins(20,20,20); self.cw=170
    def header(self):
        if self.page_no()==1: return
        self.set_y(8); self.set_font("R","B",9); self.set_text_color(*NAVY); self.cell(0,5,"STRIKER",align="L")
        self.set_font("S","",7.5); self.set_text_color(*GREY); self.set_xy(20,8); self.cell(self.cw,5,"Краткий инвестиционный меморандум",align="R")
        self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,15,190,15); self.set_y(20)
    def footer(self):
        self.set_y(-13); self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,self.get_y(),190,self.get_y())
        self.set_y(-11); self.set_font("S","",7); self.set_text_color(*GREY)
        self.cell(self.cw-20,5,"Строго конфиденциально · STRIKER · для предварительного обсуждения",align="L"); self.cell(20,5,f"{self.page_no()}",align="R")
    def section(self,num,title):
        if self.get_y()>248: self.add_page()
        self.ln(2.5); y=self.get_y()
        self.set_fill_color(*NAVY); self.rect(20,y+0.4,6.6,6.6,"F")
        self.set_font("S","B",9); self.set_text_color(*WHITE); self.set_xy(20,y+1.5); self.cell(6.6,4.4,num,align="C")
        self.set_font("R","B",12.5); self.set_text_color(*NAVY); self.set_xy(28.8,y+0.5); self.cell(0,6,title)
        self.ln(9); self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,self.get_y(),190,self.get_y()); self.ln(2)
    def fit(self,text,w=None,lh=4.6,bottom=276,extra=2):
        w=w or self.cw; self.set_font("S","",9.3)
        n=len(self.multi_cell(w,lh,text,dry_run=True,output="LINES"))
        if self.get_y()+n*lh+extra>bottom: self.add_page()
    def body(self,txt,size=9.3,after=1.6):
        self.fit(txt); self.set_font("S","",size); self.set_text_color(*INK); self.multi_cell(self.cw,4.6,txt); self.ln(after)
    def bullet(self,lead,txt,size=9.3):
        self.fit((lead or "")+txt,self.cw-5); x=20; self.set_xy(x,self.get_y())
        self.set_font("S","B",9); self.set_text_color(*ACCENT); self.cell(5,4.6,"—"); self.set_xy(x+5,self.get_y())
        if lead: self.set_font("S","B",size); self.set_text_color(*NAVY); self.write(4.6,lead)
        self.set_font("S","",size); self.set_text_color(*INK); self.write(4.6,txt); self.ln(5.2)
    def img(self,path,w=160,cap=None):
        from PIL import Image
        iw,ih=Image.open(path).size; h=w*ih/iw
        if self.get_y()+h+(5 if cap else 0)>276: self.add_page()
        x=20+(self.cw-w)/2; self.image(path,x=x,y=self.get_y(),w=w); self.set_y(self.get_y()+h+1.5)
        if cap:
            self.set_font("S","",7.6); self.set_text_color(*GREY); self.multi_cell(self.cw,3.6,cap,align="C"); self.ln(1)
    def kvtable(self,rows,kw=52):
        self.set_draw_color(*LINE); vw=self.cw-kw
        for k,v in rows:
            self.set_font("S","",8.8); n=len(self.multi_cell(vw-4,4.3,v,dry_run=True,output="LINES")); rh=max(7.0,4.3*n+3)
            if self.get_y()+rh>274: self.add_page()
            y=self.get_y(); self.set_fill_color(*SOFT); self.rect(20,y,kw,rh,"F")
            self.set_draw_color(*LINE); self.set_line_width(0.2); self.rect(20,y,kw,rh); self.rect(20+kw,y,vw,rh)
            self.set_font("S","B",8.8); self.set_text_color(*NAVY); self.set_xy(22,y+1.8); self.multi_cell(kw-3,4.3,k)
            self.set_font("S","",8.8); self.set_text_color(*INK); self.set_xy(22+kw,y+1.8); self.multi_cell(vw-4,4.3,v); self.set_y(y+rh)

p=M(); p.add_page()
# COVER
p.set_fill_color(*NAVY); p.rect(0,0,210,54,"F")
p.set_y(13); p.set_font("R","B",30); p.set_text_color(*WHITE); p.cell(0,12,"STRIKER",align="C")
p.set_font("S","",10); p.set_text_color(214,221,233); p.set_y(27); p.cell(0,5,"Проект F/A-259U · лёгкий многоцелевой боевой и учебно-боевой самолёт",align="C")
p.set_draw_color(*ACCENT); p.set_line_width(0.6); p.line(86,38,124,38)
p.set_font("S","B",10.5); p.set_text_color(*WHITE); p.set_y(41); p.cell(0,5,"КРАТКИЙ ИНВЕСТИЦИОННЫЙ МЕМОРАНДУМ",align="C")
p.set_y(60); p.set_font("S","",8.2); p.set_text_color(*GREY); p.cell(0,4,"СТРОГО КОНФИДЕНЦИАЛЬНО · ДЛЯ ПРЕДВАРИТЕЛЬНОГО ОБСУЖДЕНИЯ · 2026",align="C")
p.ln(8)
p.set_font("S","",9.0); p.set_text_color(*INK)
p.multi_cell(p.cw,4.7,"Серийное производство и поставка современного лёгкого боевого самолёта F/A-259U на проверенной сертифицированной платформе чешского производителя Aero Vodochody с новым крылом, современной авионикой и двигателем. Производство — на территории НАТО и ЕС. Документ кратко излагает проект, экономику и рекомендованную корпоративно-налоговую структуру с готовыми решениями; детальный разбор альтернатив и условия сделки — в отдельных документах (полный меморандум и term sheet).")
p.ln(2)

p.section("1","Инвестиционная теза")
p.bullet("Цель. ","Создать серийное производство современного лёгкого боевого самолёта и вывести его на мировой рынок — доступную альтернативу тяжёлым истребителям с близкими боевыми возможностями при кратно меньшей стоимости приобретения и эксплуатации.")
p.bullet("Подтверждение рыночного спроса. ","На международном авиасалоне в Ле-Бурже (Paris Air Show) заключены предварительные («мягкие») контракты — соглашения о намерениях (Letters of Intent) — на поставку 200 самолётов данной конфигурации. Эти договорённости подтверждают устойчивый рыночный интерес к машине данного класса и формируют стартовый портфель заказов проекта. Предварительные контракты подлежат переводу в твёрдые поставочные договоры на этапе оформления структуры и привлечения финансирования.")
p.bullet("Доступная многоцелевая платформа. ","Непосредственная авиаподдержка, воздушный бой, разведка, РЭБ и продвинутая подготовка лётчиков — в одном самолёте.")
p.bullet("Производство в НАТО и ЕС. ","Интеграция в оборонное сотрудничество; опора на готовый производственный опыт и проверенных мировых поставщиков.")
p.bullet("Экономика. ","Умеренные капитальные вложения относительно тяжёлых платформ при высокой совокупной прибыли и приемлемом сроке окупаемости.")

p.section("2","Продукт: F/A-259U STRIKER")
p.body("Лёгкий многоцелевой ударный и учебно-боевой самолёт на сертифицированной платформе Aero Vodochody с новым крылом, современной авионикой и двигателем. Боевые возможности: непосредственная авиаподдержка (CAS), воздушный бой и ПВО, разведка и целеуказание (ISR), радиоэлектронная борьба, продвинутая подготовка лётчиков (LIFT), совместимая с F-16 и F-35. Радар с АФАР, авионика открытой архитектуры (Link 16), семь точек подвески, высокая живучесть, эксплуатация с неподготовленных полос.")
p.kvtable([("Размах крыла / длина","9,54 м / 12,72 м"),("Макс. взлётная масса","8 300 кг"),("Полезная нагрузка","до 3 000 кг"),("Макс. скорость (у земли)","936 км/ч"),("Практический потолок","13 200 м"),("Боевые перегрузки","+8 / −4 g"),("Двигатель","АI-322F с форсажем, FADEC")],kw=52)

p.section("3","Экономика проекта")
p.bullet("Стоимость проекта — ","около 420 млн USD; вкладывается поэтапно: 1-й год 150, 2-й 170, 3-й 100 млн.")
p.bullet("Цена самолёта — ","25 млн USD; себестоимость — до 20 млн; чистая прибыль — не менее 3 млн USD на самолёт.")
p.bullet("Серийный выпуск — ","до 48 самолётов в год, всего не менее 300 машин; совокупная чистая прибыль — не менее 900 млн USD.")
p.bullet("Окупаемость — ","около 8-го года с начала финансирования (базовый сценарий); около 10-го — консервативный.")
p.img("assets_cashflow.png",w=150,cap="Накопленный денежный поток, базовый сценарий (млн USD). Точка окупаемости — между 7-м и 8-м годами.")
p.body("Ориентир для инвестора. Объём привлечения — около 420 млн USD (полное финансирование трёх лет). Ориентировочная оценка проекта (post-money) — порядка 0,7–1,1 млрд USD; совокупная доля инвесторов — ориентировочно 40–60%. Величины индикативны и уточняются по итогам переговоров и подтверждённой финансовой модели.")

p.section("4","Этапы и сроки")
p.body("От начала финансирования до старта серийного производства — 37 месяцев: до 14 мес. — двигатель, крыло, КД, макет и первый опытный; до 22 мес. — опытные образцы для испытаний крыла и вооружения; до 36 мес. — все виды испытаний и предсерийный самолёт заказчику; 37-й месяц — серийное производство.")
p.img("assets_gantt.png",w=160,cap="Календарный план от начала финансирования (месяцы).")

p.section("5","Рекомендованная структура и готовые решения")
p.body("Три уровня: инвесторы владеют единой холдинговой компанией; та напрямую владеет двумя болгарскими компаниями — производственной и продающей. На первом этапе сборку выполняет независимый чешский завод Aero Vodochody по заказу группы; на втором группа может перейти к собственному производству.")
p.img("assets_stage1.png",w=150,cap="Базовая структура (Этап 1 — производство по заказу).")
p.kvtable([("Холдинг","Великобритания — владеет проектом и правами, распределяет прибыль инвесторам"),
 ("Производственная компания","Болгария (PrincipalCo) — OEM, держатель сертификата типа и прав на разработку"),
 ("Продающая компания","Болгария (SalesCo) — держатель военно-экспортной лицензии"),
 ("Сборка","Этап 1 — Aero Vodochody (Чехия) по заказу; Этап 2 — собственный завод (Болгария или Польша)"),
 ("Права на разработку","у операционной компании (Модель 1) — прибыль облагается в Болгарии, роялти не возникает"),
 ("Налог","Болгария 10% — одна из самых низких в ЕС; наверх и инвестору — 0% удержания")],kw=52)

p.section("6","Ключевые преимущества")
p.bullet("Низкая нагрузка на прибыль. ","Операционная прибыль облагается в Болгарии по плоской ставке 10% — одной из самых низких в ЕС; плюс дешёвая рабочая сила в ЕС и логистическая близость к поставщикам.")
p.bullet("Прибыль доходит наверх без потерь. ","Передача из Болгарии в британский холдинг не облагается налогом у источника; полученные дивиденды в Великобритании освобождены.")
p.bullet("Эффективное распределение. ","Великобритания не удерживает налог на дивиденды ни при каком составе собственников — до инвестора доходит около 9/10 чистой прибыли.")
p.bullet("Надёжная юрисдикция холдинга. ","Английское право, независимые суды, развитый арбитраж — удобно для соинвестирования, финансирования и выхода.")
p.bullet("Соответствие военно-экспортным требованиям. ","Болгария и Чехия — члены НАТО и ЕС с полноценными режимами лицензирования.")
p.bullet("Защита инвестиций. ","Британский холдинг пользуется действующими договорами о защите инвестиций с Болгарией и Чехией — гарантии от экспроприации и прямой доступ к международному арбитражу против государства.")
p.bullet("Гибкость и удобный выход. ","Переход к собственному производству не требует перестройки владения; выход — продажа или IPO на уровне холдинга, прирост на уровне структуры освобождён от налога.")

p.section("7","Налоговый результат")
p.body("Прибыль облагается налогом один раз — на уровне Болгарии по ставке 10%. При передаче вверх в холдинг и далее инвесторам налога у источника не возникает.")
p.img("assets_flow.png",w=168,cap="Путь 1 млн € операционной прибыли: 10% болгарский налог — и далее без потерь до инвестора.")

p.section("8","Допуск иностранных собственников к оборонному активу")
p.body("Прямого запрета на участие иностранных, в том числе ближневосточных, инвесторов в оборонных авиапроектах НАТО и ЕС нет. Практика подтверждает: суверенный фонд Абу-Даби Mubadala владел итальянским Piaggio Aerospace; EDGE (ОАЭ) приобрёл контроль в эстонской Milrem с правовым ограждением чувствительных технологий. Допуск проходит проверку иностранных инвестиций (в ЕС — Регламент 2019/452) и обеспечивается разделением экономического участия и контроля.")
p.img("assets_control.png",w=160,cap="Прибыль получают все инвесторы; голосующий контроль и право вето — в холдинге, управление болгарскими компаниями — за лицами из стран НАТО и ЕС с допуском.")

p.section("9","Условия реализации")
p.body("Налоговые и структурные выводы действуют при реальном присутствии (управление, персонал, офис по месту регистрации) и наличии деловой цели у каждого элемента структуры. Финансовые показатели отражают оценку организаторов и подлежат подтверждению инвестором. Согласование иностранного владения с болгарским регулятором — плановый этап запуска. Детальные коммерческие условия (оценка, доли, транши, преференции, выход) изложены в отдельном документе об условиях сделки (term sheet).")
p.ln(2); p.set_font("S","",7.8); p.set_text_color(*GREY)
p.multi_cell(p.cw,3.8,"Настоящий документ носит ознакомительный характер, не является офертой, налоговой или юридической консультацией. Ставки и правовые выводы приведены по состоянию на 2026 год и подлежат подтверждению местными консультантами при внедрении структуры.")

